class Solution:
    def solve(self, arr: List[str]) -> int:
        unique = ['']
        max_len = 0
        for s in arr:
            if len(set(s)) < len(s): continue
            for u in unique:
                new_s = u + s
                if len(set(new_s)) == len(new_s):
                    unique.append(new_s)
                    max_len = max(max_len, len(new_s))
        return max_len

